// // This D flip-flop captures the input D on the falling edge of the clock and resets to 1 when the reset signal is low.
module d_flip_flop_sync_reset (
    input clk,
    input reset,
    input d,
    output reg q
);

    always @(posedge clk) begin
        if (reset)
            q <= 0;
        else
            q <= d;
    end

endmodule
